    count = 0
    for num in arr:
        # Convert to string and handle sign
        s = str(num)
        if s[0] == '-':
            # For negative numbers: first digit is negative
            total = -int(s[1])
            for digit in s[2:]:
                total += int(digit)
        else:
            # For non-negative numbers: sum all digits
            total = sum(int(d) for d in s)
        if total > 0:
            count += 1
    return count",
